// ==UserScript==
// @name         System Fonts - Fast_Serif (Fully Embedded Base64)
// @include      http*
// @locale       en
// @version      0.24
// @description  Fast_Serif everywhere – 100% self-contained, no downloads, no external files
// @author       P4Steve
// @grant        none
// @namespace    https://github.com/P4Steve 
// ==/UserScript==

(function() {
    'use strict';
    var s = document.createElement("style");
    s.type = "text/css";
    s.textContent = `
        @font-face {
            font-family: "Fast_Serif";
            src: url("data:font/ttf;base64,") format("truetype");
            font-display: swap;
        }
        * {
            font-family: "Fast_Serif", -apple-system, BlinkMacSystemFont, "SF Pro", system-ui, sans-serif !important;
        }
    `;
    document.head.appendChild(s);
})();
